// Alertmanager가 보내는 alerts[] 배열에서 firing 상태 알림만 추출
const payload = $input.first().json.body || $input.first().json;
const alerts = payload.alerts || [];

const firingAlerts = alerts.filter(a => a.status === 'firing');

if (firingAlerts.length === 0) {
  return [{ json: { skip: true, reason: 'no firing alerts' } }];
}

// 첫 번째 firing 알림 처리 (복수 알림은 각각 처리 권장)
const alert = firingAlerts[0];
const labels = alert.labels || {};
const annotations = alert.annotations || {};

return [{
  json: {
    skip: false,
    system_name: labels.system_name || labels.job || 'unknown',
    instance_role: labels.instance_role || labels.instance || '',
    alertname: labels.alertname || 'UnknownAlert',
    labels: labels,
    annotations: annotations
  }
}];

const similarity = $input.first().json;
const alertname = $('알림 파싱').first().json.alertname;
const systemName = $('알림 파싱').first().json.system_name;

const typeLabel = {
  'new':       '🆕 신규 이상',
  'related':   '🔗 유사 이상',
  'recurring': '🔁 반복 이상',
  'duplicate': '🔄 중복 이상'
}[similarity.type] || similarity.type;

const score = similarity.score ? `${(similarity.score * 100).toFixed(1)}%` : 'N/A';
const hasSolution = similarity.has_solution ? '✅ 있음' : '❌ 없음';

// 상위 유사 이력 fact 생성
const topResults = (similarity.top_results || []).slice(0, 2).map((r, i) => ({
  title: `유사 이력 ${i + 1}`,
  value: `${r.alertname || r.system_name || '?'} (${((r.score || 0) * 100).toFixed(1)}%)`
}));

return [{
  json: {
    type: 'message',
    attachments: [{
      contentType: 'application/vnd.microsoft.card.adaptive',
      content: {
        type: 'AdaptiveCard',
        version: '1.4',
        body: [
          {
            type: 'TextBlock',
            text: `📊 메트릭 이상 분석 — ${systemName}`,
            weight: 'Bolder',
            size: 'Medium'
          },
          {
            type: 'FactSet',
            facts: [
              { title: '알림명', value: alertname },
              { title: '분류', value: typeLabel },
              { title: '유사도', value: score },
              { title: '해결책', value: hasSolution },
              ...topResults
            ]
          }
        ]
      }
    }]
  }
}];
